mapper.select:
SELECT DISTINCT t_mdt_team.* FROM t_mdt_team LEFT JOIN t_mdt ON t_mdt.id = t_mdt_team.mdt_id LEFT JOIN t_mdt_tag ON t_mdt_tag.mdt_id = t_mdt.id LEFT JOIN d_mdt_tag ON d_mdt_tag.id = t_mdt_tag.tag_id LEFT JOIN t_mdt_team_tag ON t_mdt_team_tag.tag_id = d_mdt_tag.id AND t_mdt_team_tag.mdt_team_id = t_mdt_team.id LEFT JOIN t_mdt_team_doctor ON t_mdt_team.id = t_mdt_team_doctor.mdt_team_id LEFT JOIN t_doctor_user ON t_doctor_user.id = t_mdt_team_doctor.doctor_user_id LEFT JOIN t_doctor_set ON t_doctor_user.id = t_doctor_set.doctor_user_id WHERE t_mdt_team.is_delete = '0' AND t_mdt.is_delete = '0' AND t_mdt.`status` = '1' AND d_mdt_tag.`is_delete` = '0' AND t_mdt_team_doctor.doctor_type = 'CONSULTANT' AND t_doctor_user.is_auth = 'PASS' AND t_doctor_user.is_cancel = '0' AND t_doctor_user.`status` = '1' AND t_doctor_set.is_mdt = '1'
AND t_mdt_team.mdt_id = #{param1,jdbcType=VARCHAR}
AND d_mdt_tag.id = #{param2,jdbcType=VARCHAR}
ORDER BY t_mdt_team.`index`
